                preferences: SharedPreferences,
                fromKey: String,
                toCommand: ViewerCommand
            ) {
                if (!preferences.contains(fromKey)) {
                    return
                }
                val oldBindings = preferences.getString(fromKey, null) ?: return
                if (oldBindings.isBlank()) {
                    preferences.edit { remove(fromKey) }
