                val existingBindings = preferences.getString(targetKey, null) ?: ""
                val newBindings = if (existingBindings.isBlank()) {
                    oldBindings
                } else {
                    "$existingBindings|$oldBindings"
                }

                preferences.edit {
                    putString(targetKey, newBindings)
                    remove(fromKey)
                }
            }
        }
